INSERT INTO `skelbimai` (`pavadinimas`, `aprasymas`, `kaina`, `min_kiekis`, `vieta`, `data`, `amzius`, `aukstis`, `plotis`, `lotyniskas_pav`, `tipas`, `kilme`, `atstumas`, `pristatymo_budas`, `statusas`, `id_Skelbimas`, `fk_Imoneid_Imone`) VALUES
('Paprastoji pušis', 'Parduodamas sveikas, tvirtas paprastosios pušies sodinukas. Puikiai tinka sodybos apželdinimui, miško pakraščiui ar kaip akcentinis augalas jūsų kieme. Sodinukas augintas Lietuvoje, visiškai pritaikytas prie mūsų klimato sąlygų. Šaknų sistema gerai išvystyta, todėl prigijimas itin lengvas.', 15.00, 1, 'Vilnius / Vilniaus r.', '2026-05-06', 3, 45, 20, 'Pinus sylvestris', NULL, 'Lietuva', NULL, 'atsiimti_patiems', 'aktyvus', 9, 6),
('Kalninė pušis (Mugo)', 'Kompaktiška ir dekoratyvi kalninė pušis, idealiai tinkanti alpinariumams, terasoms ar mažesniems sodams. Šios rūšies pušys yra nereiklios dirvožemiui, atsparios šalčiui ir sausrai. Sodinukas yra vešlus, suformavęs gražią lają.', 25.00, 1, 'Kaunas / Kauno r.', '2026-05-06', 5, 60, 45, 'Pinus mugo', NULL, 'Lietuva', NULL, 'atsiimti_patiems', 'aktyvus', 10, 6),
('Paprastasis beržas', 'Greitai augantis, jaunas berželis, suteikiantis jaukumo jūsų sodybos ar kiemo aplinkai. Šaknų sistema pilnai prigijusi vazone. Sodinant rekomenduojama palikti mažiausiai 3 metrų atstumą nuo kitų medžių ir pastatų.', 12.00, 1, 'Vilnius / Vilniaus r.', '2026-05-06', 2, 120, 40, 'Betula pendula', NULL, 'Lietuva', NULL, 'atsiimti_patiems', 'aktyvus', 11, 6),
('Popierinis beržas', 'Dekoratyvus ir itin atsparus beržo sodinukas su gražia, balta žieve. Šviesomėgis medis, kuriam augant reikės erdvės, todėl sodinkite atsižvelgdami į 3 m atstumą nuo kitų augalų.', 18.00, 1, 'Panevėžys', '2026-05-06', 3, 150, 50, 'Betula papyrifera', NULL, 'Lietuva', NULL, 'atsiimti_patiems', 'aktyvus', 12, 6),
('Paprastoji eglė', 'Klasikinė, šalčiui atspari Lietuvos miškų eglutė. Tinka gyvatvorėms ar kaip pavienis augalas kieme. Sodinant rekomenduojama palikti bent 3.5 m tarpus tarp sodinukų, kad jie turėtų vietos šakoms plėstis.', 15.00, 1, 'Kaunas / Kauno r.', '2026-05-06', 3, 50, 30, 'Picea abies', NULL, 'Lietuva', NULL, 'atsiimti_patiems', 'aktyvus', 13, 6),
('Dygioji eglė (Sidabrinė)', 'Puošni, sidabrinio atspalvio dygioji eglė. Labai atspari šalčiui ir miesto taršai. Puikus pasirinkimas reprezentacinei kiemo zonai. Išlaikykite 3.5 m tarpus tarp sodinamų medelių.', 30.00, 1, 'Klaipėda', '2026-05-06', 4, 80, 40, 'Picea pungens', NULL, 'Lenkija', NULL, 'atsiimti_patiems', 'aktyvus', 14, 6),
('Paprastasis ąžuolas', 'Tvirtas ir ilgaamžis Lietuvos ąžuoliukas. Užaugina galingą šaknų sistemą, todėl sodinti rekomenduojama erdvesnėje vietoje, toliau nuo pastatų pamatų (rekomenduojama 6 m erdvė).', 20.00, 1, 'Šiauliai', '2026-05-06', 3, 60, 25, 'Quercus robur', NULL, 'Lietuva', NULL, 'atsiimti_patiems', 'aktyvus', 15, 6),
('Raudonasis ąžuolas', 'Sparčiau auganti ąžuolo rūšis, kuri rudenį nusidažo ryškiai raudona spalva. Puikiai tinka didesnio sklypo ar parko apželdinimui. Reikalauja mažiausiai 6 m atstumo.', 28.00, 1, 'Vilnius', '2026-05-06', 4, 90, 35, 'Quercus rubra', NULL, 'Vokietija', NULL, 'atsiimti_patiems', 'aktyvus', 16, 6),
('Paprastasis uosis', 'Tvirtas ir ilgaamžis medis, reikalauja 5 m tarpų.', 22.00, 1, 'Kaunas', '2026-05-06', 5, 180, 50, 'Fraxinus excelsior', NULL, 'Lietuva', NULL, 'atsiimti_patiems', 'aktyvus', 17, 6),
('Siauralapis uosis', 'Dekoratyvesnė uosio rūšis, puikiai tinkanti miesto želdinimui, reikalauja 5 m tarpų.', 26.00, 1, 'Vilnius', '2026-05-06', 4, 160, 40, 'Fraxinus angustifolia', NULL, 'Lietuva', NULL, 'atsiimti_patiems', 'aktyvus', 18, 6),
('Paprastasis klevas', 'Gražus lapuočių medis, reikalauja 5 m atstumo.', 25.00, 1, 'Vilnius', '2026-05-06', 4, 160, 45, 'Acer platanoides', NULL, 'Lietuva', NULL, 'atsiimti_patiems', 'aktyvus', 19, 6),
('Klevas (Uosiolis)', 'Unikalus klevas, kurio lapai primena uosio lapus, reikalauja 5 m atstumo.', 29.00, 1, 'Šiauliai', '2026-05-06', 3, 140, 35, 'Acer negundo', NULL, 'Lietuva', NULL, 'atsiimti_patiems', 'aktyvus', 20, 6),
